{"content": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>LRB Dashboard — Leon Remote Browser 🥒</title>
<style>
  :root {
    --bg: #0f0f1a;
    --surface: #1a1a2e;
    --surface2: #16213e;
    --accent: #e94560;
    --accent2: #0f3460;
    --text: #eee;
    --text2: #aaa;
    --green: #2ecc71;
    --yellow: #f1c40f;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: var(--bg);
    color: var(--text);
    padding: 20px;
    min-height: 100vh;
  }
  .container { max-width: 1200px; margin: 0 auto; }
  h1 {
    font-size: 1.5rem;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 10px;
    color: var(--accent);
  }
  h1 small { color: var(--text2); font-size: 0.8rem; font-weight: normal; }
  .grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
  @media (max-width: 800px) { .grid { grid-template-columns: 1fr; } }
  .card {
    background: var(--surface);
    border: 1px solid #2a2a4a;
    border-radius: 12px;
    padding: 16px;
    margin-bottom: 16px;
  }
  .card h2 {
    font-size: 1rem;
    color: var(--accent);
    margin-bottom: 12px;
    display: flex;
    justify-content: space-between;
    align-items: center;
  }
  .card h2 .badge {
    background: var(--accent2);
    color: var(--text);
    font-size: 0.7rem;
    padding: 2px 8px;
    border-radius: 10px;
  }
  input[type="text"], textarea {
    width: 100%;
    padding: 10px 12px;
    background: var(--surface2);
    border: 1px solid #2a2a5a;
    border-radius: 8px;
    color: var(--text);
    font-size: 0.9rem;
    margin-bottom: 8px;
  }
  input[type="text"]::placeholder, textarea::placeholder { color: #555; }
  textarea { font-family: monospace; resize: vertical; }
  button {
    padding: 8px 20px;
    border: none;
    border-radius: 8px;
    font-size: 0.85rem;
    cursor: pointer;
    font-weight: 600;
    transition: all 0.2s;
  }
  button.primary { background: var(--accent); color: white; }
  button.primary:hover { background: #d43650; }
  button.secondary { background: var(--accent2); color: var(--text); }
  button.secondary:hover { background: #1a4070; }
  button.green { background: var(--green); color: white; }
  button.green:hover { background: #27ae60; }
  button:disabled { opacity: 0.5; cursor: not-allowed; }
  button.small { padding: 4px 12px; font-size: 0.8rem; }
  .btn-group { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 8px; }

  .tab-list { list-style: none; }
  .tab-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 8px 12px;
    border-bottom: 1px solid #222;
    gap: 8px;
  }
  .tab-item:last-child { border-bottom: none; }
  .tab-info { flex: 1; overflow: hidden; }
  .tab-title { font-weight: 500; font-size: 0.85rem; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .tab-url { font-size: 0.75rem; color: var(--text2); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .tab-actions { display: flex; gap: 4px; flex-shrink: 0; }

  #screenshot-container {
    text-align: center;
    margin-top: 12px;
  }
  #screenshot-container img {
    max-width: 100%;
    max-height: 400px;
    border-radius: 8px;
    border: 1px solid #2a2a4a;
  }

  .status-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 4px 0;
    font-size: 0.85rem;
  }
  .status-row .label { color: var(--text2); }
  .status-row .value { color: var(--text); font-family: monospace; }

  .git-files {
    max-height: 200px;
    overflow-y: auto;
    background: var(--surface2);
    border-radius: 8px;
    padding: 8px;
    margin: 8px 0;
    font-family: monospace;
    font-size: 0.8rem;
  }
  .git-files .file-item {
    display: flex;
    justify-content: space-between;
    padding: 2px 4px;
  }
  .file-item .file-status {
    color: var(--yellow);
    font-weight: bold;
    margin-right: 8px;
  }
  .file-item .file-name { color: var(--text); }

  .toast {
    position: fixed;
    bottom: 20px;
    right: 20px;
    background: var(--accent2);
    color: var(--text);
    padding: 12px 20px;
    border-radius: 8px;
    font-size: 0.85rem;
    display: none;
    z-index: 100;
    animation: fadeIn 0.3s;
  }
  .toast.success { border-left: 4px solid var(--green); }
  .toast.error { border-left: 4px solid var(--accent); }
  @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

  .loading { opacity: 0.6; pointer-events: none; }

  .empty-state {
    text-align: center;
    padding: 30px;
    color: var(--text2);
  }
  .empty-state .emoji { font-size: 2rem; margin-bottom: 8px; }
</style>
</head>
<body>
<div class="container">
  <h1>🥒 LRB <small>Leon Remote Browser</small></h1>

  <div class="grid">
    <!-- Left column -->
    <div>
      <!-- Tabs -->
      <div class="card" id="tabs-card">
        <h2>📑 Open Tabs <span class="badge" id="tab-count">0</span></h2>
        <div id="tabs-container">
          <div class="empty-state"><div class="emoji">🔍</div><p>Loading tabs...</p></div>
        </div>
      </div>

      <!-- Open URL -->
      <div class="card">
        <h2>🔗 Open URL</h2>
        <form id="open-url-form">
          <input type="text" id="url-input" placeholder="https://google.com" autocomplete="off">
          <button type="submit" class="primary">Open Tab</button>
        </form>
      </div>

      <!-- Screenshot -->
      <div class="card">
        <h2>📸 Screenshot</h2>
        <div class="btn-group">
          <button id="btn-screenshot" class="secondary">Capture Active Tab</button>
        </div>
        <div id="screenshot-container"></div>
      </div>
    </div>

    <!-- Right column -->
    <div>
      <!-- Git Dashboard -->
      <div class="card">
        <h2>📦 Git Sync</h2>

        <div class="status-row">
          <span class="label">Branch</span>
          <span class="value" id="git-branch">...</span>
        </div>
        <div class="status-row">
          <span class="label">Uncommitted</span>
          <span class="value" id="git-uncommitted">...</span>
        </div>
        <div class="status-row">
          <span class="label">Last commit</span>
          <span class="value" id="git-last-commit">...</span>
        </div>

        <div id="git-files-container" style="display:none;">
          <div style="margin-top:8px; font-size:0.8rem; color:var(--text2);">Changed files:</div>
          <div class="git-files" id="git-files-list"></div>
        </div>

        <form id="commit-form" style="margin-top: 12px;">
          <input type="text" id="commit-msg" placeholder="Commit message..." autocomplete="off">
          <div class="btn-group">
            <button type="submit" class="primary">Commit & Push</button>
            <button type="button" id="btn-refresh-git" class="secondary">Refresh</button>
          </div>
        </form>
      </div>

      <!-- Recent commits -->
      <div class="card">
        <h2>🕐 Recent Commits</h2>
        <div id="recent-commits">
          <div class="empty-state"><p>Loading...</p></div>
        </div>
      </div>
    </div>
  </div>
</div>

<div class="toast" id="toast"></div>

<script>
// ============================================================
//  Toast notifications
// ============================================================
const toast = document.getElementById('toast');
function showToast(msg, type = 'success') {
  toast.textContent = msg;
  toast.className = 'toast ' + type;
  toast.style.display = 'block';
  setTimeout(() => { toast.style.display = 'none'; }, 3000);
}

// ============================================================
//  API helpers
// ============================================================
async function api(path, opts = {}) {
  try {
    const resp = await fetch(path, {
      headers: { 'Content-Type': 'application/json' },
      ...opts,
    });
    return await resp.json();
  } catch (err) {
    showToast('Network error: ' + err.message, 'error');
    return { ok: false, error: err.message };
  }
}

// ============================================================
//  Tabs
// ============================================================
async function refreshTabs() {
  const container = document.getElementById('tabs-container');
  const data = await api('/api/tabs');
  if (!data.ok) {
    container.innerHTML = '<div class="empty-state"><p>❌ Cannot connect to Chromium</p></div>';
    return;
  }

  const tabs = data.tabs || [];
  document.getElementById('tab-count').textContent = tabs.length;

  if (tabs.length === 0) {
    container.innerHTML = '<div class="empty-state"><div class="emoji">🪟</div><p>No open tabs</p></div>';
    return;
  }

  let html = '<ul class="tab-list">';
  for (const tab of tabs) {
    const url = tab.url.length > 60 ? tab.url.substring(0, 60) + '...' : tab.url;
    const title = tab.title.length > 50 ? tab.title.substring(0, 50) + '...' : tab.title;
    html += `
      <li class="tab-item">
        <div class="tab-info">
          <div class="tab-title">${escapeHtml(title || '(untitled)')}</div>
          <div class="tab-url">${escapeHtml(url || '(blank)')}</div>
        </div>
        <div class="tab-actions">
          <button class="small secondary" onclick="screenshotTab('${tab.id}')">📸</button>
          <button class="small secondary" onclick="closeTab('${tab.id}')">✕</button>
        </div>
      </li>
    `;
  }
  html += '</ul>';
  container.innerHTML = html;
}

async function openTab(url) {
  const data = await api('/api/open', {
    method: 'POST',
    body: JSON.stringify({ url }),
  });
  if (data.ok) {
    showToast(`Opened: ${data.tab?.title || url}`);
    refreshTabs();
  } else {
    showToast('Error: ' + (data.error || 'unknown'), 'error');
  }
}

async function closeTab(id) {
  const data = await api('/api/close', {
    method: 'POST',
    body: JSON.stringify({ id }),
  });
  if (data.ok) {
    showToast('Tab closed');
    refreshTabs();
  }
}

async function screenshotTab(id) {
  const container = document.getElementById('screenshot-container');
  container.innerHTML = '<p style="color:var(--text2)">Capturing...</p>';
  const img = document.createElement('img');
  const params = id ? `?id=${encodeURIComponent(id)}` : '';
  img.src = `/api/screenshot${params}&t=${Date.now()}`;
  img.onload = () => { container.innerHTML = ''; container.appendChild(img); };
  img.onerror = () => { container.innerHTML = '<p style="color:var(--accent)">Screenshot failed</p>'; };
}

// ============================================================
//  Git
// ============================================================
async function refreshGit() {
  const data = await api('/api/git/status');
  if (!data.ok) {
    document.getElementById('git-uncommitted').textContent = 'Error';
    return;
  }

  const s = data.status;

  if (s.files.length > 0) {
    document.getElementById('git-uncommitted').textContent = `${s.count} files (${formatSize(s.totalSize)})`;

    const container = document.getElementById('git-files-container');
    container.style.display = 'block';
    const list = document.getElementById('git-files-list');
    list.innerHTML = s.files.map(f => 
      `<div class="file-item">
        <span><span class="file-status">${f.status === '?' ? '?' : 'M'}</span><span class="file-name">${escapeHtml(f.file)}</span></span>
      </div>`
    ).join('');
  } else {
    document.getElementById('git-uncommitted').textContent = 'Clean ✓';
    document.getElementById('git-files-container').style.display = 'none';
  }

  // Recent commits
  const commitsContainer = document.getElementById('recent-commits');
  if (data.recentCommits.length > 0) {
    commitsContainer.innerHTML = data.recentCommits.map(c => {
      const [hash, ...rest] = c.split(' ');
      return `<div class="status-row"><span class="value">${hash}</span><span style="color:var(--text2)">${escapeHtml(rest.join(' '))}</span></div>`;
    }).join('');
  }

  // Try to get branch
  document.getElementById('git-branch').textContent = 'main';

  // Last commit
  if (data.recentCommits.length > 0) {
    document.getElementById('git-last-commit').textContent = data.recentCommits[0].split(' ')[0] + ' - see above';
  }
}

async function commitPush(message) {
  const data = await api('/api/git/commit', {
    method: 'POST',
    body: JSON.stringify({ message }),
  });
  if (data.ok) {
    showToast('✅ ' + (data.commit || data.note || 'Done!'));
    refreshGit();
    refreshTabs();
  } else {
    showToast('❌ ' + (data.error || 'Failed'), 'error');
  }
}

// ============================================================
//  Utilities
// ============================================================
function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

function formatSize(bytes) {
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / 1048576).toFixed(1) + ' MB';
}

// ============================================================
//  Event handlers
// ============================================================

// Open URL form
document.getElementById('open-url-form').addEventListener('submit', (e) => {
  e.preventDefault();
  const input = document.getElementById('url-input');
  const url = input.value.trim() || 'https://google.com';
  // Auto-add https:// if missing
  const finalUrl = url.startsWith('http://') || url.startsWith('https://') ? url : 'https://' + url;
  openTab(finalUrl);
  input.value = '';
});

// Commit form
document.getElementById('commit-form').addEventListener('submit', (e) => {
  e.preventDefault();
  const input = document.getElementById('commit-msg');
  const msg = input.value.trim();
  if (!msg) {
    showToast('Please enter a commit message', 'error');
    return;
  }
  commitPush(msg);
  input.value = '';
});

document.getElementById('btn-refresh-git').addEventListener('click', refreshGit);
document.getElementById('btn-screenshot').addEventListener('click', () => screenshotTab(null));

// ============================================================
//  Auto-refresh
// ============================================================
refreshTabs();
refreshGit();
setInterval(refreshTabs, 5000);
setInterval(refreshGit, 15000);
</script>
</body>
</html>
